// js/questions-y7.js — Year 7 NSW Science question bank (syllabus-aligned, regenerated)
window.QUESTION_BANK = window.QUESTION_BANK || {};
window.QUESTION_BANK[7] = {
  "universe": [
    { q: "What is the main purpose of science?", o: ["To win arguments using facts", "To build knowledge and understanding of the world through observation, experimentation and analysis", "To prove that all ancient ideas are wrong", "To create new technology"], a: 1, exp: "Science builds reliable knowledge by testing ideas against evidence gathered through observation, experimentation and analysis." },
    { q: "Which ancient model placed Earth at the centre of the solar system?", o: ["Heliocentric model", "Geocentric model", "Elliptical model", "Copernican model"], a: 1, exp: "The geocentric model, developed by Ptolemy around 150 CE, placed Earth at the centre with the Sun and planets orbiting around it." },
    { q: "Who published the first widely known heliocentric model of the solar system?", o: ["Galileo Galilei", "Isaac Newton", "Nicolaus Copernicus", "Johannes Kepler"], a: 2, exp: "Nicolaus Copernicus published his heliocentric (Sun-centred) model in 1543." },
    { q: "What shape are the orbits of planets according to the modern model?", o: ["Perfect circles", "Spirals", "Ellipses", "Squares"], a: 2, exp: "Johannes Kepler discovered that planets orbit the Sun in ellipses, not perfect circles." },
    { q: "Which observation by Galileo most strongly challenged the geocentric model?", o: ["He saw craters on the Moon", "He discovered moons orbiting Jupiter", "He measured the temperature of stars", "He counted the number of planets"], a: 1, exp: "Moons orbiting Jupiter proved that not everything in the universe orbits Earth, undermining the geocentric model." },
    { q: "What causes day and night on Earth?", o: ["Earth orbiting the Sun", "The Moon blocking sunlight", "Earth rotating on its own axis", "The Sun moving around Earth"], a: 2, exp: "Day and night are caused by Earth rotating on its axis once every approximately 24 hours." },
    { q: "What causes the seasons on Earth?", o: ["Earth moving closer to and further from the Sun", "Earth's axial tilt as it orbits the Sun", "The Moon's gravity pulling on Earth", "Changes in the Sun's brightness"], a: 1, exp: "Earth's axial tilt of 23.5 degrees means different hemispheres receive more direct sunlight at different times of year, causing seasons." },
    { q: "How long does it take for the Moon to complete one full cycle of phases?", o: ["24 hours", "7 days", "Approximately 29.5 days", "365 days"], a: 2, exp: "The lunar cycle (new Moon to new Moon) takes approximately 29.5 days." },
    { q: "Why does the Moon appear to change shape each night?", o: ["The Moon rotates and we see different sides", "Earth's shadow falls on the Moon each night", "We see different fractions of the Moon's sunlit side as it orbits Earth", "The Moon grows and shrinks physically"], a: 2, exp: "As the Moon orbits Earth, we see changing fractions of the sunlit hemisphere, creating the phases." },
    { q: "Does the Moon produce its own light?", o: ["Yes, from nuclear reactions on its surface", "Yes, it glows due to heat", "No, it reflects light from the Sun", "No, its light comes from Earth"], a: 2, exp: "The Moon has no light of its own; it reflects sunlight from the Sun." },
    { q: "A solar eclipse occurs when:", o: ["Earth passes between the Sun and the Moon", "The Moon passes between Earth and the Sun", "The Sun passes between Earth and the Moon", "Earth is at its furthest from the Sun"], a: 1, exp: "A solar eclipse happens when the Moon passes directly between Earth and the Sun, blocking sunlight from reaching part of Earth." },
    { q: "A lunar eclipse occurs when:", o: ["The Moon passes between Earth and the Sun", "Earth passes between the Sun and the Moon", "The Sun is blocked by clouds", "The Moon is at new Moon phase"], a: 1, exp: "A lunar eclipse occurs when Earth passes between the Sun and the Moon, casting Earth's shadow on the Moon." },
    { q: "Why does the Moon turn reddish-orange during a total lunar eclipse?", o: ["The Moon's surface heats up and glows", "Earth's atmosphere bends red sunlight into the shadow", "The Moon reflects the red colour of the ocean", "Dust on the Moon reflects red light"], a: 1, exp: "Earth's atmosphere refracts (bends) some red wavelengths of sunlight around Earth and into the shadow, giving the Moon a reddish colour." },
    { q: "Why don't eclipses happen every new Moon and every full Moon?", o: ["The Moon is too small to cast a shadow", "The Moon's orbit is tilted about 5 degrees to Earth's orbital plane so it usually passes above or below the shadow", "The Sun is too far away", "Earth moves too fast in its orbit"], a: 1, exp: "The Moon's orbit is tilted about 5 degrees relative to Earth's orbit around the Sun, so the Moon usually misses the shadow at new Moon and full Moon." },
    { q: "What is a spring tide?", o: ["A tide that only occurs in spring", "An unusually low tide", "A stronger tide that occurs when the Sun, Earth and Moon are aligned", "A tide caused by earthquakes"], a: 2, exp: "Spring tides occur at new Moon and full Moon when the Sun, Earth and Moon align, combining their gravitational pull for a larger tidal range." },
    { q: "What is a neap tide?", o: ["The highest tide of the year", "A weaker tide that occurs at the quarter Moon phases", "A tide caused by storms", "A tide caused by the Sun alone"], a: 1, exp: "Neap tides occur at first and last quarter when the Moon is at right angles to the Earth-Sun line, producing weaker tides." },
    { q: "What force causes ocean tides on Earth?", o: ["Earth's rotation", "Solar wind", "The Moon's gravitational pull on Earth's oceans", "Earth's axial tilt"], a: 2, exp: "The Moon's gravity pulls on Earth's oceans, creating bulges of water that produce tides as Earth rotates." },
    { q: "Approximately how long does it take Earth to orbit the Sun once?", o: ["24 hours", "29.5 days", "365.25 days", "27 days"], a: 2, exp: "Earth takes approximately 365.25 days (one year) to complete one orbit of the Sun." },
    { q: "What is Earth's axial tilt approximately?", o: ["0 degrees", "10 degrees", "23.5 degrees", "45 degrees"], a: 2, exp: "Earth's axis is tilted at approximately 23.5 degrees relative to the plane of its orbit." },
    { q: "In science, what is a 'theory'?", o: ["A guess or hunch about something", "A well-tested, widely accepted explanation for a broad range of observations", "A law that never changes", "An opinion held by most scientists"], a: 1, exp: "A scientific theory is a well-tested explanation supported by extensive evidence, not a simple guess." },
    { q: "How does a scientific law differ from a scientific theory?", o: ["A law is more certain and cannot change", "A theory explains observations; a law describes a precise pattern or relationship", "A law is proved and a theory is not", "They are the same thing"], a: 1, exp: "A theory explains why something happens; a law (often a mathematical relationship) describes precisely what happens without necessarily explaining why." },
    { q: "What type of orbit does the International Space Station follow?", o: ["It orbits the Moon", "It orbits the Sun", "It orbits Earth", "It stays stationary in space"], a: 2, exp: "The ISS orbits Earth at an altitude of approximately 400 km, completing about 16 orbits per day." },
    { q: "The Yolngu people of Arnhem Land traditionally understood the connection between:", o: ["The Sun's position and rainfall", "The Moon's phases and tidal patterns", "Stars and temperature", "Wind direction and ocean depth"], a: 1, exp: "The Yolngu people linked the Moon's phases to tidal cycles, teaching that the Moon fills with water as it waxes and empties as it wanes." },
    { q: "Why can Aboriginal and Torres Strait Islander peoples use the position of certain stars to predict seasonal events?", o: ["Stars move closer to Earth in certain seasons", "Earth's orbit around the Sun changes which stars are visible at different times of year", "Stars change colour with the seasons", "The Moon blocks certain stars in summer"], a: 1, exp: "As Earth orbits the Sun, different stars become visible in the night sky at different times of year, making star positions reliable seasonal calendars." },
    { q: "Which Aboriginal group used the rising of the Pleiades to signal the eel harvesting season?", o: ["Yolngu people", "Noongar people", "Boorong people of Victoria", "Warlpiri people"], a: 2, exp: "The Boorong people of north-western Victoria used the appearance of the Pleiades (which they called Karakarook) to signal the eel harvesting season." },
    { q: "What is the 'Emu in the Sky' in Aboriginal astronomy?", o: ["A bright star named after an emu", "A dark constellation formed by the dark patches of the Milky Way", "A group of stars that look like an emu", "A comet that appears each year"], a: 1, exp: "The Emu in the Sky is formed by the dark dust clouds within the Milky Way, and its seasonal position signals the time of emu egg laying." },
    { q: "How many seasons do the Noongar people of south-western Western Australia recognise?", o: ["Two", "Four", "Six", "Eight"], a: 2, exp: "The Noongar people recognise six seasons, each defined by a combination of weather, star positions, plant flowering and animal behaviour." },
    { q: "What is an observation in science?", o: ["A conclusion based on data", "A guess about what will happen", "A direct measurement or description detected by the senses or instruments", "An opinion about a scientific topic"], a: 2, exp: "An observation is a direct measurement or description of something detected using the senses or instruments." },
    { q: "What is an inference in science?", o: ["A direct measurement using an instrument", "A logical conclusion drawn from observations that goes beyond what was directly measured", "A prediction that has been tested and confirmed", "A type of graph used to show data"], a: 1, exp: "An inference is a logical conclusion drawn from one or more observations, going beyond what was directly detected." },
    { q: "What is the 'sensitivity' of a measuring instrument?", o: ["How accurately it reads the true value", "The range of values it can measure", "The smallest change in a quantity it can detect", "Whether the instrument is analog or digital"], a: 2, exp: "Sensitivity is the smallest change in a quantity that an instrument can detect — a more sensitive instrument detects smaller differences." },
    { q: "Which type of measuring instrument generally has higher sensitivity: analog or digital?", o: ["Analog instruments are always more sensitive", "Digital instruments generally have higher sensitivity", "They always have the same sensitivity", "Sensitivity depends only on price"], a: 1, exp: "Digital instruments typically have higher sensitivity (can detect smaller changes) and provide more precise numerical readings than analog instruments." },
    { q: "What is the 'range' of a measuring instrument?", o: ["The accuracy of its measurements", "The minimum to maximum values it can measure", "The number of decimal places it shows", "How long it lasts before breaking"], a: 1, exp: "The range of an instrument is the span from the minimum to maximum values it can measure." },
    { q: "What is the independent variable in a scientific investigation?", o: ["The variable that is measured as a result", "The variable that is deliberately changed by the scientist", "A variable kept constant throughout the experiment", "The quantity shown on the y-axis"], a: 1, exp: "The independent variable is the one the scientist deliberately changes to see what effect it has on the dependent variable." },
    { q: "What is the dependent variable in a scientific investigation?", o: ["The variable the scientist changes", "The variable kept constant throughout", "The variable that is measured as a result of changing the independent variable", "Any variable in the experiment"], a: 2, exp: "The dependent variable is measured or observed; it depends on (responds to) changes in the independent variable." },
    { q: "Why do scientists repeat experiments multiple times and calculate an average?", o: ["To make the experiment take longer", "To increase reliability and reduce the effect of random errors", "To use up all available materials", "Because a single trial result is always wrong"], a: 1, exp: "Repeating experiments and averaging results increases reliability by reducing the effect of random errors or unusual one-off results." },
    { q: "What advantage do scientific instruments have over unaided human senses?", o: ["Instruments are always free to use", "Instruments can detect beyond the range of senses and give precise, consistent numerical values", "Human senses are always unreliable", "Instruments are more portable than senses"], a: 1, exp: "Instruments extend beyond the limits of human senses, detecting phenomena we cannot perceive and providing consistent, precise measurements." },
    { q: "When is a line graph the most appropriate type to use?", o: ["When comparing categories of data", "When showing parts of a whole", "When both variables are continuous (measured over a range)", "When data has no pattern"], a: 2, exp: "Line graphs are used when both the independent and dependent variables are continuous, such as temperature over time." },
    { q: "The geocentric model was widely accepted for over 1400 years mainly because:", o: ["It was mathematically the simplest model", "It agreed with the observation that the sky appears to move around a stationary Earth and matched religious views of Earth's importance", "It was based on telescope observations", "It correctly predicted all planetary positions"], a: 1, exp: "The geocentric model agreed with the everyday observation of the sky moving around a stationary Earth and was supported by philosophical and religious beliefs." },
    { q: "What did Galileo observe about Venus that supported the heliocentric model?", o: ["Venus had moons of its own", "Venus showed phases, indicating it orbits the Sun", "Venus was the largest planet", "Venus had a surface like Earth"], a: 1, exp: "Galileo observed that Venus shows a complete set of phases (like the Moon), which could only occur if Venus orbits the Sun rather than Earth." },
    { q: "Which force keeps the Moon in orbit around Earth?", o: ["Magnetic force", "Friction", "Electrostatic force", "Gravitational force"], a: 3, exp: "The Moon is kept in its orbit by Earth's gravitational pull, which continuously pulls the Moon inward even as it moves forward." },
    { q: "What is the name of the phase when the Moon is between Earth and the Sun?", o: ["Full Moon", "First quarter", "New Moon", "Last quarter"], a: 2, exp: "At new Moon, the Moon is between Earth and the Sun; its lit side faces away from us so it is not visible at night." },
    { q: "At which Moon phase would a total solar eclipse potentially occur?", o: ["Full Moon", "First quarter", "Last quarter", "New Moon"], a: 3, exp: "A solar eclipse requires the Moon to be between Earth and the Sun, which can only happen at new Moon phase." },
    { q: "At which Moon phase would a total lunar eclipse potentially occur?", o: ["New Moon", "First quarter", "Full Moon", "Last quarter"], a: 2, exp: "A lunar eclipse requires Earth to be between the Sun and Moon, which only happens when the Moon is full." },
    { q: "Why do astronauts on the ISS appear to float?", o: ["There is no gravity in space", "The ISS turns off gravity inside", "The astronauts and ISS are in continuous free fall around Earth together", "Magnetic fields cancel gravity inside the ISS"], a: 2, exp: "The ISS and astronauts are both in continuous free fall around Earth (orbiting), so they fall together and experience apparent weightlessness." },
    { q: "What is redshift in astronomy?", o: ["The red colour of stars near the Sun", "The shift of light towards longer wavelengths from objects moving away from us", "The reddening of the sky at sunrise", "A type of telescope filter"], a: 1, exp: "Redshift is the stretching of light towards longer (redder) wavelengths, observed from galaxies moving away from us, providing evidence the universe is expanding." },
    { q: "The James Webb Space Telescope primarily observes in which type of light?", o: ["Visible light", "Ultraviolet light", "X-ray light", "Infrared light"], a: 3, exp: "The JWST observes in infrared light, allowing it to see through dust clouds and detect very distant or dust-obscured objects." },
    { q: "Which three space agencies collaborated to build the James Webb Space Telescope?", o: ["NASA, JAXA and ESA", "NASA, ESA and the Canadian Space Agency", "ESA, ISRO and NASA", "NASA, SpaceX and ESA"], a: 1, exp: "The JWST was built through an international collaboration between NASA, ESA (Europe) and the Canadian Space Agency." },
    { q: "Why is it said that science 'builds on the work of others'?", o: ["Scientists always copy each other's work", "New knowledge extends and uses findings from previous scientists, creating a growing body of shared knowledge", "Scientists must repeat all previous experiments before doing new ones", "Science never changes once established"], a: 1, exp: "Each generation of scientists extends and refines what came before; for example, Kepler's work built on Copernicus, and Einstein's on Newton." },
    { q: "What does 'working scientifically' involve?", o: ["Only doing experiments in a laboratory", "Using processes such as questioning, planning, conducting investigations, analysing data and communicating findings", "Reading about science in textbooks", "Making observations but not experiments"], a: 1, exp: "Working scientifically is a framework of processes scientists use: questioning, planning, conducting, processing data, problem-solving and communicating." },
    { q: "Which Aboriginal peoples use the rising of the Pleiades to signal the beginning of the trade wind season?", o: ["Boorong people", "Noongar people", "Torres Strait Islander peoples", "Warlpiri people"], a: 2, exp: "In Torres Strait, the rising of the Pleiades in May signals the beginning of the trade wind season, guiding when and where communities fish." },
    { q: "When scientists communicate findings through peer-reviewed publications, what is the main benefit?", o: ["It makes scientists famous", "It allows the wider community to evaluate, replicate and build upon the work", "It ensures only one scientist's view is accepted", "It stops other scientists from doing similar research"], a: 1, exp: "Peer-reviewed publications allow other scientists to critically evaluate, replicate and extend the work, strengthening the reliability of scientific knowledge." },
    { q: "What is a 'controlled variable' in an experiment?", o: ["The variable that is deliberately changed", "The variable that is measured", "A variable that is kept the same throughout to make it a fair test", "A variable that cannot be measured"], a: 2, exp: "Controlled variables are those kept constant throughout the experiment so that only the independent variable's effect is measured." },
    { q: "What does 'waxing' mean when describing the Moon's phases?", o: ["The Moon is getting smaller (less lit area visible)", "The Moon is getting larger (more lit area becoming visible)", "The Moon is full", "The Moon is at new phase"], a: 1, exp: "Waxing means the lit portion of the Moon visible from Earth is increasing, from new Moon toward full Moon." },
    { q: "What does 'waning' mean when describing the Moon's phases?", o: ["The Moon is getting larger", "The Moon is at full phase", "The lit portion visible from Earth is decreasing, from full Moon back toward new Moon", "The Moon is rising in the east"], a: 2, exp: "Waning means the lit portion of the Moon visible from Earth is decreasing, moving from full Moon back toward new Moon." },
    { q: "Which of the following is an example of systematic observation in astronomy?", o: ["A single measurement of a star's brightness", "Monitoring sunspot activity continuously over decades to find an 11-year cycle", "One experiment testing telescope filters in a laboratory", "A single photograph of a nebula"], a: 1, exp: "Systematic observation involves standardised, regular measurements over time; decades of sunspot monitoring revealed an 11-year solar cycle." },
    { q: "What is a scientific model?", o: ["A miniature physical object", "A representation based on data and observations of a real-world phenomenon", "A guess about how something works", "A rule that describes nature mathematically"], a: 1, exp: "A scientific model is a representation (physical, mathematical or conceptual) based on evidence, used to explain or predict phenomena." }
  ],
  "forces": [
    { q: "What is a force?", o: ["A measurement of temperature", "A push or a pull", "The mass of an object", "The speed of a moving object"], a: 1, exp: "A force is a push or a pull that can change an object's shape, speed or direction of movement." },
    { q: "What is the unit used to measure force?", o: ["Kilogram (kg)", "Metre (m)", "Newton (N)", "Joule (J)"], a: 2, exp: "Force is measured in newtons (N), named after Sir Isaac Newton." },
    { q: "Which of the following is a contact (direct) force?", o: ["Gravity", "Magnetic force", "Electrostatic force", "Friction"], a: 3, exp: "Friction is a contact force because it only acts when two surfaces are touching each other." },
    { q: "Which of the following is a non-contact (indirect) force?", o: ["Applied force", "Tension", "Gravity", "Air resistance"], a: 2, exp: "Gravity is a non-contact force because it acts across a distance without objects needing to touch." },
    { q: "Which THREE forces are classified as non-contact in Year 7?", o: ["Friction, tension and gravity", "Gravity, magnetic force and electrostatic force", "Applied force, buoyancy and friction", "Gravity, tension and normal force"], a: 1, exp: "The three non-contact forces in Year 7 are gravity (between masses), magnetic force (between magnets or magnetic materials) and electrostatic force (between electric charges)." },
    { q: "What are balanced forces?", o: ["Forces that are both pointing in the same direction", "Forces that cancel each other out so the object's motion does not change", "Forces that always make an object speed up", "Two forces that are equal but both pointing up"], a: 1, exp: "Balanced forces are equal and opposite, resulting in a net force of zero, so the object's motion does not change." },
    { q: "What is the net force on a stationary book sitting on a table?", o: ["Equal to the weight of the book", "Double the weight of the book", "Zero, because gravity and the support force are balanced", "Equal to the support force only"], a: 2, exp: "The downward gravitational force and the upward support (normal) force are equal and opposite, giving a net force of zero." },
    { q: "In a force diagram, what does a longer arrow represent?", o: ["A slower force", "A force acting for a longer time", "A larger (stronger) force", "A force in an unknown direction"], a: 2, exp: "In force diagrams, the length of an arrow represents the magnitude (size) of the force — longer means stronger." },
    { q: "A shopping trolley has 80 N pushing right and 30 N friction pushing left. What is the net force?", o: ["110 N to the right", "50 N to the left", "50 N to the right", "30 N to the right"], a: 2, exp: "Net force = 80 N right minus 30 N left = 50 N to the right; the trolley will accelerate to the right." },
    { q: "What happens to an object when forces acting on it are unbalanced?", o: ["It stays still", "Its motion does not change", "It changes speed or direction", "It instantly stops"], a: 2, exp: "Unbalanced forces produce a net force, which causes the object to speed up, slow down or change direction." },
    { q: "What does F = mg represent?", o: ["The formula for weight: weight force (N) equals mass (kg) times gravitational field strength (N/kg)", "Force equals mass times gravity — a formula for momentum", "Friction equals mass times grip", "Force equals metres times grams"], a: 0, exp: "F = mg is the formula for weight: weight force (F, in newtons) equals mass (m, in kg) multiplied by gravitational field strength (g, in N/kg)." },
    { q: "What is the approximate value of g (gravitational field strength) on Earth?", o: ["1.6 N/kg", "3.7 N/kg", "9.8 N/kg", "100 N/kg"], a: 2, exp: "On Earth, g is approximately 9.8 N/kg (often rounded to 10 N/kg for simple calculations)." },
    { q: "A student has a mass of 50 kg. What is their weight on Earth? (g = 10 N/kg)", o: ["50 N", "500 N", "5 N", "50 kg"], a: 1, exp: "Weight = m x g = 50 x 10 = 500 N. Weight is measured in newtons, not kilograms." },
    { q: "What is the difference between mass and weight?", o: ["They are the same thing, just different units", "Mass is the force of gravity; weight is how much matter the object contains", "Mass (kg) measures amount of matter and does not change with location; weight (N) is the gravitational force on that mass and changes with location", "Mass changes with location; weight never changes"], a: 2, exp: "Mass (kg) is the amount of matter and does not change. Weight (N) is the gravitational force on the mass and changes with the gravitational field strength." },
    { q: "An astronaut has a mass of 70 kg on Earth. What is their mass on the Moon?", o: ["About 11.5 kg, because g is weaker", "About 70 N", "70 kg, because mass does not change with location", "About 686 N"], a: 2, exp: "Mass does not change with location — an astronaut with a mass of 70 kg on Earth still has a mass of 70 kg on the Moon." },
    { q: "On the Moon, g is approximately 1.6 N/kg. What is the weight of a 40 kg object on the Moon?", o: ["40 N", "64 N", "392 N", "400 N"], a: 1, exp: "Weight on Moon = m x g = 40 x 1.6 = 64 N. The object weighs much less on the Moon than on Earth." },
    { q: "What causes objects to stay in orbit around Earth?", o: ["There is no gravity in orbit", "A rocket engine pushes them continuously", "Gravity pulls them inward while their forward speed curves their path around Earth", "Magnetic forces between Earth and the satellite"], a: 2, exp: "A satellite moves forward very fast; gravity pulls it inward. These two effects combine so the satellite continuously curves around Earth — that is an orbit." },
    { q: "Which force keeps the Moon in orbit around Earth?", o: ["Magnetism", "Friction", "Electrostatic force", "Gravity"], a: 3, exp: "Earth's gravitational pull keeps the Moon in its orbit by continuously pulling it inward." },
    { q: "Which rule describes how opposite electric charges behave?", o: ["Opposite charges repel each other", "Opposite charges attract each other", "Like charges attract each other", "Electric charges have no effect on each other"], a: 1, exp: "Opposite electric charges (positive and negative) attract each other; like charges (both positive or both negative) repel each other." },
    { q: "A balloon rubbed on hair sticks to a wall. Which force is responsible?", o: ["Gravity", "Magnetic force", "Electrostatic force", "Friction"], a: 2, exp: "Rubbing the balloon on hair transfers electrons, making the balloon negatively charged. This electrostatic charge causes it to attract the wall." },
    { q: "Is gravity always attractive, always repulsive, or can it be either?", o: ["Always repulsive", "Can be either, depending on masses", "Always attractive — gravity never pushes", "Repulsive between large masses, attractive between small masses"], a: 2, exp: "Gravity is always a force of attraction — it always pulls masses toward each other and never pushes them apart." },
    { q: "What are the two poles of a magnet called?", o: ["East and west", "Positive and negative", "North and south", "Top and bottom"], a: 2, exp: "Every magnet has two poles: a north pole and a south pole." },
    { q: "Two north poles of magnets are brought close together. What happens?", o: ["They attract each other strongly", "They have no effect on each other", "They repel each other", "One loses its magnetism"], a: 2, exp: "Like poles (north-north or south-south) repel each other; opposite poles (north-south) attract." },
    { q: "Which of these materials is attracted to a magnet?", o: ["Aluminium", "Copper", "Iron (steel)", "Plastic"], a: 2, exp: "Iron, nickel and cobalt (and steel, which contains iron) are ferromagnetic materials attracted to magnets. Aluminium, copper and most other metals are not." },
    { q: "What is a magnetic field?", o: ["The force a magnet exerts on people", "The area around a magnet where its force can be felt", "The pattern of iron atoms inside a magnet", "The north pole of a magnet"], a: 1, exp: "A magnetic field is the region around a magnet where its magnetic force can be detected by other magnets or magnetic materials." },
    { q: "Magnetic field lines always leave which pole of a magnet?", o: ["South pole", "North pole", "Either pole", "The middle of the magnet"], a: 1, exp: "By convention, magnetic field lines leave the north pole and enter the south pole of a magnet." },
    { q: "What does it mean when magnetic field lines are closer together?", o: ["The magnet is at a lower temperature", "The field is stronger in that region", "The field is weaker in that region", "The magnet is about to break"], a: 1, exp: "Where field lines are closer together, the magnetic field is stronger. Field lines are closest together near the poles of a magnet." },
    { q: "What is an electromagnet?", o: ["A permanent magnet made from steel", "A magnet created by electric current flowing through a coil of wire around an iron core", "A compass needle", "A magnet made from aluminium"], a: 1, exp: "An electromagnet is made by passing electric current through a coil of wire around an iron core. It is magnetic only when current flows." },
    { q: "What is one advantage of an electromagnet over a permanent magnet?", o: ["Electromagnets are always stronger", "Electromagnets can be switched on and off", "Electromagnets work without electricity", "Electromagnets never lose their magnetism"], a: 1, exp: "An electromagnet can be switched on and off by controlling the current, making it useful in cranes, MRI machines and door locks." },
    { q: "How can you make an electromagnet stronger?", o: ["Use fewer turns of wire and a weaker battery", "Use more turns of wire around the core and increase the current", "Remove the iron core", "Use a plastic core instead of iron"], a: 1, exp: "Increasing the number of turns of wire, using a larger current, or using an iron core all make an electromagnet stronger." },
    { q: "What is a simple machine?", o: ["Any electrical device that makes life easier", "A basic device that makes work easier by changing the direction or size of a force", "A machine with fewer than five parts", "An automated robotic tool"], a: 1, exp: "A simple machine is a basic device (such as a lever, pulley, or ramp) that makes work easier by changing the size or direction of a force." },
    { q: "Which of the following is an example of a lever?", o: ["A ramp", "A pulley wheel", "A crowbar", "A screw"], a: 2, exp: "A crowbar is a lever; it rotates around a fulcrum (pivot point) to lift or move heavy objects with less force." },
    { q: "What does a ramp (inclined plane) allow you to do?", o: ["Increase the total work done", "Lift an object using less force by pushing it over a longer distance", "Cut through materials", "Change direction of force from horizontal to downward"], a: 1, exp: "A ramp allows you to move something to a height using less force, but you must push it over a longer distance — total work done remains the same." },
    { q: "What is the fulcrum of a lever?", o: ["The load that is being moved", "The force applied to the lever", "The pivot point around which the lever rotates", "The length of the lever arm"], a: 2, exp: "The fulcrum is the fixed pivot point around which a lever rotates." },
    { q: "In a first-class lever, where is the fulcrum?", o: ["At one end, next to the load", "At one end, next to the effort force", "Between the load and the effort force", "There is no fulcrum in a first-class lever"], a: 2, exp: "In a first-class lever, the fulcrum is between the load and the effort. A seesaw is a classic example." },
    { q: "A wheelbarrow is an example of which class of lever?", o: ["First class (fulcrum between load and effort)", "Second class (load between fulcrum and effort)", "Third class (effort between fulcrum and load)", "It is not a lever"], a: 1, exp: "A wheelbarrow is a second-class lever: the wheel is the fulcrum at one end, the load is in the middle, and you push at the handles (effort)." },
    { q: "What is mechanical advantage?", o: ["How fast a machine moves", "How many times a simple machine multiplies the input force (load divided by effort)", "The total energy used by a machine", "The distance an object moves with a machine"], a: 1, exp: "Mechanical advantage (MA) = load divided by effort. A machine with MA of 3 means you only need one-third the force to move the load." },
    { q: "What does a single fixed pulley on a flagpole do?", o: ["Reduces the force needed to raise the flag", "Doubles the distance you must pull", "Changes the direction of the force (you pull down to make the flag go up) but does not reduce the force required", "Provides no benefit at all"], a: 2, exp: "A single fixed pulley changes the direction of force (pull down to lift up) but has a mechanical advantage of 1 — it does not reduce the required force." },
    { q: "The woomera used by many Aboriginal Nations is an example of which simple machine?", o: ["An inclined plane", "A lever", "A pulley", "A wedge"], a: 1, exp: "The woomera acts as a lever, extending the thrower's arm to increase the speed and force of a thrown spear." },
    { q: "What force principle do the Brewarrina stone fish traps use?", o: ["Magnetic force to attract fish", "The force of moving water, channelled through narrow openings to trap fish", "Gravity to pull fish up from the riverbed", "Electrostatic force to stun fish"], a: 1, exp: "The Brewarrina fish traps use carefully placed rocks to channel the force of flowing water through narrow openings where fish can be caught." },
    { q: "What energy transfer occurs when you rub your hands together?", o: ["Chemical energy to electrical energy", "Kinetic energy to thermal energy (heat)", "Gravitational potential energy to kinetic energy", "Electrical energy to light energy"], a: 1, exp: "Friction (a contact force) converts kinetic energy (movement) into thermal energy (heat) when you rub your hands together." },
    { q: "What type of energy is stored in a stretched rubber band?", o: ["Chemical energy", "Thermal energy", "Elastic potential energy", "Gravitational potential energy"], a: 2, exp: "A stretched rubber band stores elastic potential energy; when released, this converts to kinetic energy." },
    { q: "A dog has a mass of 25 kg. What is its weight on Earth? (g = 9.8 N/kg)", o: ["25 N", "245 N", "2.55 N", "250 kg"], a: 1, exp: "Weight = m x g = 25 x 9.8 = 245 N." },
    { q: "An object has a weight of 49 N on Earth. What is its mass? (g = 9.8 N/kg)", o: ["49 kg", "480 kg", "5 kg", "0.2 kg"], a: 2, exp: "m = F / g = 49 / 9.8 = 5 kg." },
    { q: "How does the gravitational force between two objects change as they get further apart?", o: ["It increases", "It stays the same", "It decreases", "It reverses direction"], a: 2, exp: "Gravitational force decreases as the distance between objects increases — similar to magnetic and electrostatic forces." },
    { q: "Which technique did many Aboriginal groups use involving friction to make fire?", o: ["Lens focusing sunlight", "Fire drill — spinning a hardwood stick rapidly against a softer wood base", "Striking two stones together only", "Chemical reactions with plant sap"], a: 1, exp: "Fire drills and fire saws use friction (a contact force) to convert kinetic energy into thermal energy, generating temperatures above 300 degrees C to ignite tinder." },
    { q: "What force acts upward on an object resting on a table?", o: ["Gravity", "Tension", "Normal (support) force", "Friction"], a: 2, exp: "The normal (support) force is the upward force a surface exerts on an object resting on it, balancing gravity." },
    { q: "Tweezers are an example of which class of lever?", o: ["First class", "Second class", "Third class", "Fourth class"], a: 2, exp: "Tweezers are third-class levers: the effort (squeeze with fingers) is between the fulcrum (the hinge end) and the load (what is being gripped)." },
    { q: "A rocket launching has more thrust upward than weight downward. What happens?", o: ["The forces are balanced and the rocket stays still", "The net force is downward and the rocket stays on the pad", "The net upward force causes the rocket to accelerate upward", "The rocket moves sideways"], a: 2, exp: "When thrust exceeds weight, there is a net upward force, so the rocket accelerates upward." },
    { q: "What does a force diagram show?", o: ["The path an object travels", "All the forces acting on an object, drawn as arrows showing size and direction", "Only the largest force on an object", "The energy stored in an object"], a: 1, exp: "A force diagram shows all forces on an object as arrows: the direction shows which way each force acts, and arrow length shows the force's magnitude." },
    { q: "When a skydiver reaches terminal velocity after opening their parachute, what is true?", o: ["The downward gravity force is larger than air resistance", "Air resistance is larger than gravity", "Gravity and air resistance are balanced, so the skydiver falls at constant speed", "There are no forces acting on the skydiver"], a: 2, exp: "At terminal velocity, air resistance (up) equals weight (down) — forces are balanced and the skydiver falls at constant speed." },
    { q: "Which of the following is NOT one of the six classical simple machines?", o: ["Lever", "Pulley", "Electric motor", "Wedge"], a: 2, exp: "The six classical simple machines are lever, pulley, wheel and axle, inclined plane, wedge and screw. An electric motor is not a simple machine." },
    { q: "What physical principle does a screw exploit?", o: ["It is a lever that rotates", "It is an inclined plane wrapped around a cylinder; turning it drives it forward", "It uses magnetic force to grip wood", "It is a wedge that splits apart material"], a: 1, exp: "A screw is essentially an inclined plane wrapped around a cylinder; each turn converts rotational force into linear penetration." },
    { q: "The Budj Bim eel trap system was built and maintained by which people?", o: ["Wiradjuri People", "Noongar People", "Gunditjmara People of south-western Victoria", "Arrernte People"], a: 2, exp: "The Budj Bim eel trap system in south-western Victoria was built and maintained by the Gunditjmara People over more than 6600 years." },
    { q: "A box has 25 N pushing left and 40 N pushing right. What is the net force and which way does the box move?", o: ["65 N to the right", "15 N to the right", "15 N to the left", "65 N to the left"], a: 1, exp: "Net force = 40 N right minus 25 N left = 15 N to the right. The box accelerates to the right." },
    { q: "What are the three effects a force can have on an object?", o: ["Colour, temperature and shape changes", "Change its shape, change its speed, or change its direction of movement", "Change its mass, colour or temperature", "Increase its weight, volume or speed only"], a: 1, exp: "A force can change an object's shape, change how fast it is moving (speed up or slow down), or change the direction it is moving." },
    { q: "Which of the six classical simple machines is a wedge?", o: ["A jar lid", "A flagpole rope system", "An axe used to split wood", "A wheel on an axle"], a: 2, exp: "An axe (or any knife or chisel) is a wedge — two inclined planes back-to-back that convert a downward push into a sideways splitting force." }
  ],
  "cells": [
    { q: "What mnemonic is used to remember the seven characteristics of living things?", o: ["HOMES", "MRSGREN", "LIVING", "BIOMED"], a: 1, exp: "MRSGREN stands for Movement, Reproduction, Sensitivity, Growth, Respiration, Excretion and Nutrition — the seven characteristics of living things." },
    { q: "Which of the following is NOT one of the seven characteristics of living things?", o: ["Respiration", "Reproduction", "Combustion", "Excretion"], a: 2, exp: "Combustion is a chemical reaction, not a life process. The seven characteristics are Movement, Reproduction, Sensitivity, Growth, Respiration, Excretion and Nutrition." },
    { q: "What is excretion in living organisms?", o: ["Eating food for energy", "The removal of metabolic waste products produced by the organism's own cells", "Passing out undigested food", "Reproducing to make offspring"], a: 1, exp: "Excretion is the removal of waste products made by the organism's own metabolism (such as urea and carbon dioxide), not undigested food." },
    { q: "A sunflower turning to face the Sun is an example of which characteristic of living things?", o: ["Reproduction", "Sensitivity (responding to a stimulus)", "Nutrition", "Excretion"], a: 1, exp: "Sensitivity is the ability to detect and respond to stimuli in the environment. A sunflower turning toward light is responding to a light stimulus." },
    { q: "What is biological classification?", o: ["Collecting organisms to sell", "The process of grouping organisms based on shared characteristics so that patterns in nature can be recognised", "Studying how organisms move", "Counting the number of species in an area"], a: 1, exp: "Classification is the systematic grouping of organisms based on shared features, allowing scientists to organise and study the diversity of life." },
    { q: "Who introduced the binomial naming system and approximately when?", o: ["Charles Darwin, 1859", "Carl Linnaeus, 1758", "Robert Hooke, 1665", "Louis Pasteur, 1860"], a: 1, exp: "Swedish naturalist Carl Linnaeus introduced the binomial system in 1758, giving every species a unique two-part Latin name." },
    { q: "How is a scientific species name (binomial name) correctly written?", o: ["Both parts in capitals: HOMO SAPIENS", "First part capitalised, second lowercase, both in italics: Homo sapiens", "Both parts in lowercase italics: homo sapiens", "First lowercase, second in capitals: homo Sapiens"], a: 1, exp: "The genus name has a capital first letter; the species name is entirely lowercase; both are written in italics (or underlined when handwritten)." },
    { q: "Which mnemonic helps remember the order of classification ranks from broadest to most specific?", o: ["MRS GREN", "HOMES", "Kings Play Chess On Fine Green Silk", "Never Eat Soggy Waffles"], a: 2, exp: "Kings Play Chess On Fine Green Silk represents Kingdom, Phylum, Class, Order, Family, Genus, Species." },
    { q: "Which is the MOST specific level of biological classification?", o: ["Kingdom", "Class", "Genus", "Species"], a: 3, exp: "Species is the most specific level; organisms in the same species can interbreed to produce fertile offspring." },
    { q: "Which is the BROADEST (least specific) level of biological classification?", o: ["Family", "Kingdom", "Phylum", "Genus"], a: 1, exp: "Kingdom is the broadest level of the traditional classification hierarchy, grouping the most diverse range of organisms together." },
    { q: "If two organisms share the same genus but different species names, how are they related?", o: ["They are identical organisms", "They are closely related but distinct species", "They are from completely different kingdoms", "They share no characteristics at all"], a: 1, exp: "Sharing the same genus means they are closely related and share many features, but they are distinct species that typically cannot interbreed." },
    { q: "What is a dichotomous key used for?", o: ["Unlocking laboratory storage", "Identifying unknown organisms by working through a series of paired statements about observable features", "Measuring the size of organisms", "Drawing biological diagrams"], a: 1, exp: "A dichotomous key allows users to identify an unknown organism by choosing between pairs of statements about observable features at each step." },
    { q: "What does 'dichotomous' mean?", o: ["Having many branches", "Having no branches", "Divided into two choices at each step", "Relating to plants only"], a: 2, exp: "Dichotomous means 'divided into two'; at each step of the key, you choose between exactly two alternative statements." },
    { q: "An organism has 8 legs and no antennae. Which class does it belong to?", o: ["Insecta", "Chilopoda", "Arachnida", "Diplopoda"], a: 2, exp: "Arachnids (spiders, scorpions, mites) have 8 legs and no antennae. Insects have 6 legs; centipedes and millipedes have more." },
    { q: "State the first statement of cell theory.", o: ["All cells contain chloroplasts", "All living things are made of one or more cells", "Cells can arise from non-living matter", "All cells are identical in structure"], a: 1, exp: "The first statement of cell theory is: all living things are made of one or more cells — from the simplest bacteria to blue whales." },
    { q: "Who first used the word 'cell' to describe what he saw under a microscope?", o: ["Anton van Leeuwenhoek", "Theodor Schwann", "Robert Hooke in 1665", "Rudolf Virchow"], a: 2, exp: "Robert Hooke first used the word 'cell' in 1665 when he observed cork tissue under his microscope and described the small compartments he saw." },
    { q: "What does the third statement of cell theory say?", o: ["The cell is the smallest unit of life", "All organisms are made of cells", "All cells arise from pre-existing cells", "Cells require oxygen to survive"], a: 2, exp: "The third statement, contributed by Rudolf Virchow in 1855, states that all cells come from pre-existing cells — life does not arise from non-living matter." },
    { q: "What is the function of the cell membrane?", o: ["Provides rigid shape and support for the cell", "Contains DNA that controls cell activities", "Site of cellular respiration", "Controls what enters and exits the cell — a selective barrier"], a: 3, exp: "The cell membrane is a thin flexible layer that acts as a selective barrier, allowing useful substances in and waste products out." },
    { q: "What is the function of the nucleus in a cell?", o: ["Site of photosynthesis", "Contains DNA and acts as the control centre, directing cell activities", "Stores water and waste", "Produces energy for the cell"], a: 1, exp: "The nucleus contains the cell's DNA (genetic material) and acts as the control centre for growth, metabolism and reproduction." },
    { q: "Where does cellular respiration take place in a cell?", o: ["Chloroplasts", "Cell membrane", "Cytoplasm only", "Mitochondria"], a: 3, exp: "Cellular respiration takes place in mitochondria, where glucose is broken down with oxygen to release energy." },
    { q: "Where does photosynthesis take place in a plant cell?", o: ["Mitochondria", "Nucleus", "Chloroplasts", "Cell membrane"], a: 2, exp: "Photosynthesis occurs in chloroplasts, which contain chlorophyll — the green pigment that absorbs light energy to make glucose." },
    { q: "Which structure is found in plant cells but NOT in animal cells?", o: ["Cell membrane", "Mitochondria", "Nucleus", "Cell wall made of cellulose"], a: 3, exp: "Plant cells have a rigid cell wall made of cellulose outside the cell membrane; animal cells have no cell wall." },
    { q: "Name THREE structures found in plant cells but NOT in animal cells.", o: ["Nucleus, mitochondria and ribosomes", "Cell wall, chloroplasts and large central vacuole", "Cytoplasm, nucleus and ribosomes", "Cell membrane, nucleus and mitochondria"], a: 1, exp: "Plant cells have a cellulose cell wall, chloroplasts (for photosynthesis) and a large central vacuole (for water storage) — all absent in animal cells." },
    { q: "What is the role of mitochondria in a cell?", o: ["They control cell division", "They produce glucose from sunlight", "They carry out aerobic cellular respiration to release energy (ATP)", "They store water for the cell"], a: 2, exp: "Mitochondria are the sites of aerobic cellular respiration, breaking down glucose to release energy stored as ATP for the cell's activities." },
    { q: "What is the word equation for aerobic cellular respiration?", o: ["Glucose + water produces oxygen + carbon dioxide", "Carbon dioxide + water produces glucose + oxygen", "Glucose + oxygen produces carbon dioxide + water + energy", "Oxygen + glucose produces water + sunlight + energy"], a: 2, exp: "Glucose + oxygen produces carbon dioxide + water + energy (ATP). Mitochondria carry out this reaction to release usable energy." },
    { q: "What is the word equation for photosynthesis?", o: ["Glucose + oxygen produces carbon dioxide + water", "Carbon dioxide + water (plus light energy) produces glucose + oxygen", "Glucose + water produces oxygen + sunlight", "Oxygen + carbon dioxide produces glucose + water"], a: 1, exp: "Photosynthesis: carbon dioxide + water (using light energy) produces glucose + oxygen. This happens in chloroplasts." },
    { q: "How does the shape of a typical plant cell differ from a typical animal cell?", o: ["Animal cells are always rectangular; plant cells are always round", "Plant cells tend to be rectangular and regular (due to cell wall); animal cells are more irregular in shape", "Both always have the same shape", "Animal cells are larger and more regular than plant cells"], a: 1, exp: "Plant cells are typically rectangular and regular in shape because of their rigid cellulose cell wall; animal cells are more varied and irregular." },
    { q: "What does the large central vacuole in a plant cell do?", o: ["Carries out photosynthesis", "Stores water, maintains turgor pressure and helps keep the cell rigid", "Controls cell division", "Produces proteins for the cell"], a: 1, exp: "The large central vacuole stores water and other substances, helping maintain turgor pressure that keeps the plant cell rigid and upright." },
    { q: "Why do root hair cells have long, thin extensions?", o: ["To carry out photosynthesis more efficiently", "To increase surface area for absorbing water and minerals from the soil", "To move the plant through the soil", "To store sugar produced by the leaves"], a: 1, exp: "Root hair cells have a long thin extension that dramatically increases the surface area in contact with soil water, improving absorption of water and minerals." },
    { q: "What is the function of red blood cells?", o: ["To fight infections in the blood", "To carry oxygen around the body, packed with haemoglobin", "To form blood clots when injured", "To produce antibodies"], a: 1, exp: "Red blood cells are packed with haemoglobin and have a biconcave disc shape with no nucleus, maximising oxygen-carrying capacity." },
    { q: "What is a tissue in biology?", o: ["A group of organs working together", "A single specialised cell", "A group of similar cells working together to perform a specific function", "The outer covering of an organism"], a: 2, exp: "A tissue is a group of similar cells (sometimes a few closely associated types) that work together to perform a specific function." },
    { q: "What is an organ in biology?", o: ["A single type of tissue", "A structure made up of several types of tissue working together to perform a complex function", "A group of organisms living together", "A single specialised cell with many nuclei"], a: 1, exp: "An organ (such as the heart or leaf) is made of several tissue types working together to perform a complex function." },
    { q: "What does a guard cell do in a plant leaf?", o: ["Absorbs water from the soil", "Produces glucose by photosynthesis in the leaf interior", "Controls the opening and closing of stomata for gas exchange and water loss", "Transports glucose to the roots"], a: 2, exp: "Guard cells are kidney-shaped cells that change shape with water content, controlling the size of the stomata (pores) for gas exchange and water regulation." },
    { q: "Under a microscope, a student sees cells with: rectangular shape, clearly visible cell wall, and a large central clear space. What type of cell is this?", o: ["Animal cell (cheek cell)", "Bacterial cell", "Plant cell", "Fungal cell (yeast)"], a: 2, exp: "Rectangular shape, visible cell wall and large central vacuole are distinctive features of plant cells." },
    { q: "How is total magnification calculated for a compound microscope?", o: ["Add the eyepiece and objective magnifications", "Divide the objective by the eyepiece magnification", "Multiply the eyepiece magnification by the objective magnification", "Use only the objective magnification"], a: 2, exp: "Total magnification = eyepiece magnification x objective magnification. For example, 10x eyepiece x 40x objective = 400x total." },
    { q: "What stain is typically used to make the nucleus of animal cells (such as cheek cells) more visible?", o: ["Iodine solution", "Methylene blue", "Safranin", "Congo red"], a: 1, exp: "Methylene blue stains nuclei dark blue, making them more visible in animal cells under the microscope." },
    { q: "Why do bacteria appear so different from plant and animal cells under a light microscope?", o: ["Bacteria are larger than plant and animal cells", "Bacteria are prokaryotes — they are much smaller and have no membrane-bound nucleus or organelles", "Bacteria always move too fast to observe", "Bacteria cannot be stained with standard stains"], a: 1, exp: "Bacteria are prokaryotes: they are typically much smaller than eukaryotic cells and lack a membrane-bound nucleus and organelles." },
    { q: "How does Aboriginal and Torres Strait Islander classification of organisms differ from the Linnaean system?", o: ["It is based on DNA analysis", "It groups organisms by their uses, cultural significance, ecological roles and relationships to Country, not just physical similarity", "It uses fewer categories than the Linnaean system", "It is based entirely on colour"], a: 1, exp: "Indigenous classification systems organise organisms according to their uses, cultural significance, ecological roles and relationships to Country, not just physical features." },
    { q: "What does photosynthesis produce that cellular respiration uses as a reactant?", o: ["Carbon dioxide and water", "Oxygen and glucose", "ATP and water", "Carbon dioxide and ATP"], a: 1, exp: "Photosynthesis produces glucose and oxygen; aerobic cellular respiration uses glucose and oxygen as its reactants." },
    { q: "Why does an animal cell NOT need a cell wall?", o: ["Animal cells always live in water of exactly the same concentration", "Animal cells are protected by blood proteins", "Animal cells are flexible enough to cope with slight volume changes and are supported by the organism's homeostatic systems", "Animal cells produce their own rigid wall out of protein"], a: 2, exp: "Animal cells lack a rigid cell wall but tolerate water changes through cell membrane flexibility and the organism's homeostatic systems." },
    { q: "What is the function of chlorophyll in plant cells?", o: ["To break down glucose for energy", "To absorb light energy for photosynthesis", "To control which substances enter the cell", "To produce ATP in the mitochondria"], a: 1, exp: "Chlorophyll is the green pigment in chloroplasts that absorbs light energy, which is then used to drive the photosynthesis reaction." },
    { q: "Why does a nerve cell (neuron) have a very long axon?", o: ["To carry out photosynthesis over a large area", "To store large amounts of energy", "To transmit electrical signals rapidly over long distances through the body", "To absorb more oxygen from the blood"], a: 2, exp: "Neurons have very long axons to allow rapid transmission of electrical signals over long distances, connecting distant parts of the body." },
    { q: "What does MRSGREN stand for?", o: ["Movement, Reproduction, Sight, Growth, Respiration, Excretion, Nutrition", "Movement, Reproduction, Sensitivity, Growth, Respiration, Excretion, Nutrition", "Metabolism, Reproduction, Sensitivity, Growth, Respiration, Energy, Nutrition", "Movement, Reproduction, Sensitivity, Growth, Respiration, Energy, Nutrition"], a: 1, exp: "MRSGREN: Movement, Reproduction, Sensitivity, Growth, Respiration, Excretion, Nutrition — the seven characteristics of living things." },
    { q: "Approximately how many species are estimated to exist on Earth?", o: ["87 000", "870 000", "8.7 million", "87 billion"], a: 2, exp: "Approximately 8.7 million species are estimated to exist on Earth, with new species discovered every year." },
    { q: "What is a structural adaptation?", o: ["A behaviour that helps an organism survive", "A physical feature of an organism's body that helps it survive in its environment", "An internal body process that helps survival", "A change in DNA due to environmental pressure"], a: 1, exp: "A structural adaptation is a physical feature of the body (such as the thorny devil's channels for collecting dew) that improves survival or reproduction." },
    { q: "What are the three statements of cell theory?", o: ["All cells contain chloroplasts; cells divide every 24 hours; all cells have a nucleus", "All living things are made of cells; the cell is the basic unit of life; all cells arise from pre-existing cells", "Cells are made of atoms; all cells respire; cells are the same size", "All living things grow; cells contain DNA; cells cannot die"], a: 1, exp: "Cell theory: (1) all living things are made of cells; (2) the cell is the basic structural and functional unit of life; (3) all cells arise from pre-existing cells." },
    { q: "What is the function of cytoplasm?", o: ["To provide rigid structural support for the cell", "To absorb light energy for photosynthesis", "To provide a fluid medium inside the cell where chemical reactions occur and organelles are suspended", "To control what enters and exits the cell"], a: 2, exp: "Cytoplasm is the gel-like fluid that fills the cell, providing a medium for chemical reactions and suspending the organelles." },
    { q: "Why is the palisade mesophyll tissue near the top of a leaf?", o: ["To protect the leaf from insects", "Because it is tightly packed with chloroplast-rich cells positioned to capture maximum light just below the upper surface", "To prevent water loss from the leaf", "To allow gas exchange at the leaf surface"], a: 1, exp: "Palisade mesophyll cells are column-shaped and packed with chloroplasts, positioned near the top of the leaf to absorb maximum sunlight for photosynthesis." },
    { q: "How many pairs of legs do insects have?", o: ["4 pairs (8 legs)", "3 pairs (6 legs)", "5 pairs (10 legs)", "2 pairs (4 legs)"], a: 1, exp: "Insects (Class Insecta) have exactly 3 pairs of legs (6 legs) and 3 body regions (head, thorax, abdomen)." },
    { q: "What type of organisms are bacteria: prokaryotes or eukaryotes?", o: ["Eukaryotes — they have a membrane-bound nucleus", "Prokaryotes — they have no membrane-bound nucleus or organelles", "Neither — they are not cellular organisms", "Eukaryotes — they have mitochondria"], a: 1, exp: "Bacteria are prokaryotes: they lack a membrane-bound nucleus; their DNA floats freely in the cytoplasm." },
    { q: "Which feature distinguishes a plant cell from a fungal cell under the microscope?", o: ["Plant cells have a cell wall; fungal cells do not", "Plant cells have a nucleus; fungal cells do not", "Plant cells in green parts contain chloroplasts; fungal cells do not", "Plant cells are much smaller than fungal cells"], a: 2, exp: "Both plant and fungal cells have a cell wall, but plant cells (in green parts) contain chloroplasts for photosynthesis, while fungal cells do not." },
    { q: "What is a behavioural adaptation? Give an example from an Australian animal.", o: ["A physical body feature, such as a hard shell", "A way an organism acts that helps it survive, such as being nocturnal to avoid desert heat", "An internal chemical process, such as enzyme production", "A change in body colour due to the environment"], a: 1, exp: "A behavioural adaptation is something an organism does (not a body structure) to aid survival. Many desert animals are nocturnal, avoiding the hottest part of the day." },
    { q: "What is the correct format for the binomial name of the domestic cat, Felis catus?", o: ["FELIS CATUS", "felis catus", "Felis catus (genus capitalised, species lowercase, both in italics)", "Felis Catus"], a: 2, exp: "The genus name starts with a capital letter; the species name is all lowercase; both are italicised (or underlined in handwriting)." },
    { q: "Why do scientists use a standardised classification system using Latin names rather than common names?", o: ["Latin sounds more scientific", "Latin names are the same worldwide, allowing scientists of all languages to communicate precisely about the same organism", "Common names are always wrong", "Latin names are easier to remember than common names"], a: 1, exp: "Latin binomial names are universal — the same name is used by scientists in every country and language, preventing confusion from multiple common names." },
    { q: "What is the level of organisation in a multicellular organism from smallest to largest?", o: ["Tissue, cell, organ, organism", "Cell, tissue, organ, organism", "Organ, tissue, cell, organism", "Organism, organ, cell, tissue"], a: 1, exp: "The correct order from smallest to largest is: cell, tissue, organ, organ system, organism." },
    { q: "Why can a specialised cell (like a red blood cell) not survive independently?", o: ["It has too much DNA", "It is too large to exist on its own", "It has lost the ability to perform all life functions on its own and depends on other cell types to supply what it cannot produce", "It does not have a cell membrane"], a: 2, exp: "Specialised cells give up some general functions to excel at one task; they therefore depend on other cell types in the organism for their survival." }
  ],
  "solutions": [
    { q: "What are the three states of matter?", o: ["Solid, plasma and gas", "Solid, liquid and gas", "Liquid, vapour and crystal", "Solid, liquid and steam"], a: 1, exp: "The three states of matter are solid, liquid and gas. Water is unique in existing naturally in all three states at Earth's surface temperatures." },
    { q: "Which state of matter has particles in a fixed, regular arrangement that can only vibrate in place?", o: ["Gas", "Liquid", "Solid", "Plasma"], a: 2, exp: "In a solid, particles are tightly and regularly packed; they vibrate in fixed positions but cannot move from place to place." },
    { q: "Which state of matter can be easily compressed into a smaller volume?", o: ["Solid", "Liquid", "Gas", "All three states equally"], a: 2, exp: "Gases can be compressed significantly because there is a large amount of empty space between their particles. Solids and liquids resist compression." },
    { q: "What is the melting point of water at standard atmospheric pressure?", o: ["100 degrees Celsius", "0 degrees Celsius", "-10 degrees Celsius", "37 degrees Celsius"], a: 1, exp: "Water melts (ice to liquid water) at 0 degrees Celsius at standard atmospheric pressure." },
    { q: "What is the boiling point of water at standard atmospheric pressure?", o: ["0 degrees Celsius", "37 degrees Celsius", "50 degrees Celsius", "100 degrees Celsius"], a: 3, exp: "Water boils (liquid to gas) at 100 degrees Celsius at standard atmospheric pressure." },
    { q: "What is the name for the change of state from liquid to gas?", o: ["Melting", "Condensation", "Freezing", "Evaporation (or boiling)"], a: 3, exp: "Evaporation (slow) and boiling (rapid, throughout the liquid) are both names for the liquid-to-gas change of state." },
    { q: "What is the name for the change of state from gas to liquid?", o: ["Evaporation", "Sublimation", "Condensation", "Melting"], a: 2, exp: "Condensation is the change of state from gas to liquid; energy is released as gas particles slow down and come together." },
    { q: "What is sublimation?", o: ["Liquid changing directly to a gas", "Solid changing directly to a gas, skipping the liquid state", "Gas changing to a solid", "The freezing of a liquid"], a: 1, exp: "Sublimation is when a solid changes directly to a gas without first becoming a liquid. Dry ice (solid CO2) sublimes at room temperature." },
    { q: "Why does temperature remain constant during a change of state (for example, while ice is melting)?", o: ["Because the Bunsen burner is turned off during melting", "Because energy added is used to break forces between particles rather than raise their kinetic energy (temperature)", "Because water does not absorb heat", "Because particles stop moving during melting"], a: 1, exp: "During a change of state, the energy added goes into breaking (or forming) the forces between particles rather than increasing temperature, so temperature stays constant." },
    { q: "Using particle theory, why does a gas fill its entire container while a solid holds its own shape?", o: ["Gas particles are smaller than solid particles", "Gas particles move freely in all directions with weak attractive forces; solid particles are held in fixed positions by strong forces", "Gas particles are heavier than solid particles", "Solid particles are electrically charged; gas particles are not"], a: 1, exp: "In a gas, attractive forces are negligible and particles move rapidly in all directions, filling any space. In a solid, strong forces lock particles in fixed positions." },
    { q: "What is the formula for calculating density?", o: ["Density = mass + volume", "Density = volume divided by mass", "Density = mass divided by volume", "Density = mass times volume"], a: 2, exp: "Density (rho) = mass (m) divided by volume (V). Units are commonly g/mL or g/cm cubed for school work." },
    { q: "A block has a mass of 120 g and a volume of 40 cm cubed. What is its density?", o: ["4800 g/cm cubed", "0.33 g/cm cubed", "3 g/cm cubed", "80 g/cm cubed"], a: 2, exp: "Density = mass / volume = 120 / 40 = 3 g/cm cubed." },
    { q: "What is the approximate density of water?", o: ["0.5 g/mL", "1.0 g/mL", "2.7 g/mL", "10 g/mL"], a: 1, exp: "Water has a density of approximately 1.0 g/mL (or 1000 kg/m cubed). Objects less dense than 1.0 g/mL float in water." },
    { q: "A piece of wood has a density of 0.7 g/mL. Will it float or sink in water?", o: ["Sink, because it is denser than water", "Float, because it is less dense than water", "Float, because wood is always buoyant", "Sink, because wood absorbs water"], a: 1, exp: "Objects less dense than water (1.0 g/mL) float. Wood at 0.7 g/mL is less dense than water, so it floats." },
    { q: "How do you measure the volume of an irregularly shaped object in the laboratory?", o: ["Use a ruler to measure its dimensions", "Use the water displacement method: submerge it in a measuring cylinder and read the rise in water level", "Estimate its volume by eye", "Weigh it and divide by density"], a: 1, exp: "The water displacement method: place the object in a measured volume of water in a measuring cylinder; the rise in water level equals the object's volume." },
    { q: "Why does ice float on liquid water?", o: ["Ice is lighter in colour so it floats", "Ice particles are more energetic than liquid water particles", "Ice is less dense than liquid water because its crystal structure has more open spacing", "Ice has no mass so gravity does not pull it down"], a: 2, exp: "When water freezes, it forms a regular hexagonal lattice that takes up more space, making ice (about 0.917 g/mL) less dense than liquid water (1.0 g/mL)." },
    { q: "What is surface tension in water?", o: ["The temperature at which water turns to steam", "A thin elastic 'skin' on the water surface caused by unequal attractive forces on surface molecules", "The pressure of water on the walls of a container", "The ability of water to flow downhill"], a: 1, exp: "Surface tension arises because water molecules at the surface are pulled inward and sideways but not upward, creating a skin-like elastic layer." },
    { q: "What is a solution?", o: ["Any mixture of two or more substances", "A homogeneous mixture where one substance (solute) is dissolved evenly throughout another (solvent)", "A liquid that has been purified by distillation", "A compound made of two elements"], a: 1, exp: "A solution is a homogeneous (uniform) mixture formed when a solute dissolves completely and evenly in a solvent." },
    { q: "In a solution of salt dissolved in water, what is the solute?", o: ["Water", "Salt", "The resulting solution", "Both water and salt equally"], a: 1, exp: "The solute is the substance that dissolves (salt). The solvent is the substance it dissolves in (water). The result is the solution." },
    { q: "What does 'soluble' mean?", o: ["A substance that melts when heated", "A substance that can dissolve in a given solvent", "A substance that floats in water", "A substance that reacts with acids"], a: 1, exp: "A soluble substance can dissolve in a solvent; an insoluble substance cannot. Salt and sugar are soluble in water; sand and chalk are insoluble." },
    { q: "Which of the following substances is INSOLUBLE in water?", o: ["Table salt (sodium chloride)", "Sugar (sucrose)", "Sand (silicon dioxide)", "Copper sulfate"], a: 2, exp: "Sand (silicon dioxide) is insoluble in water — it does not dissolve and settles to the bottom of the container." },
    { q: "What is a saturated solution?", o: ["A very dilute solution", "A solution that contains the maximum amount of dissolved solute possible at that temperature", "A solution where the solvent has evaporated", "Any solution that is strongly coloured"], a: 1, exp: "A saturated solution holds the maximum possible amount of dissolved solute for that temperature. Adding more solute will leave it undissolved at the bottom." },
    { q: "How does increasing temperature generally affect the solubility of a solid solute in water?", o: ["Solubility decreases as temperature increases", "Solubility stays the same regardless of temperature", "Solubility increases as temperature increases (for most solids)", "Solubility increases but then suddenly decreases above 50 degrees C"], a: 2, exp: "For most solid solutes, solubility increases with temperature because faster-moving water particles can more effectively separate and surround solute particles." },
    { q: "How does increasing temperature affect the solubility of a gas dissolved in water?", o: ["Gas solubility increases as temperature increases", "Gas solubility is not affected by temperature", "Gas solubility decreases as temperature increases", "Gas solubility doubles for every 10 degree rise"], a: 2, exp: "The solubility of gases in water decreases with increasing temperature, which is why fish can be stressed in warm water with less dissolved oxygen." },
    { q: "Why do bubbles appear inside a saucepan before the water even reaches boiling point?", o: ["Oxygen is being produced by a chemical reaction in the water", "Dissolved gases become less soluble as water warms and escape from solution as bubbles", "The metal pan reacts with water to produce gas", "Water molecules break apart into hydrogen and oxygen when warm"], a: 1, exp: "As water warms, the solubility of dissolved gases (like CO2 and O2) decreases, so gas comes out of solution as bubbles before boiling even begins." },
    { q: "What is a supersaturated solution?", o: ["A very concentrated solution", "A solution that has been filtered to remove all impurities", "An unstable solution that contains MORE dissolved solute than the saturation point normally allows", "A solution with two different solvents"], a: 2, exp: "A supersaturated solution is made by dissolving solute at high temperature and carefully cooling it. It is unstable — any disturbance causes rapid crystallisation." },
    { q: "How would you separate sand from water using a common laboratory technique?", o: ["Evaporation", "Distillation", "Filtration", "Chromatography"], a: 2, exp: "Filtration separates an insoluble solid (sand) from a liquid (water) using filter paper; sand particles are too large to pass through, while water molecules are not." },
    { q: "How would you separate salt from a salt-water solution in the laboratory?", o: ["Filtration", "Magnetic separation", "Evaporation (heating until water evaporates, leaving salt crystals)", "Distillation"], a: 2, exp: "Evaporation is used to separate a dissolved solid from a solution by driving off the solvent. The salt remains as crystals after the water evaporates." },
    { q: "What physical property does filtration exploit to separate mixtures?", o: ["Boiling point", "Magnetic properties", "Particle size (the filter paper's small pores block large particles but allow small ones through)", "Density"], a: 2, exp: "Filtration exploits differences in particle size; the filter paper's small pores allow liquid and dissolved particles through but block larger solid particles." },
    { q: "What separation technique would you use to separate iron filings from sand?", o: ["Filtration", "Evaporation", "Distillation", "Magnetic separation"], a: 3, exp: "Iron is a ferromagnetic material attracted to magnets, while sand is not. A magnet can pull iron filings away from sand." },
    { q: "What is distillation used for?", o: ["Separating an insoluble solid from a liquid", "Separating a dissolved solid from a solution", "Separating two liquids with different boiling points", "Separating magnetic and non-magnetic materials"], a: 2, exp: "Distillation separates two or more liquids by exploiting their different boiling points. One liquid vaporises first, is collected and condensed separately." },
    { q: "What is the difference between an element and a compound?", o: ["An element has two types of atoms; a compound has one", "An element contains only one type of atom; a compound contains two or more types of atoms chemically bonded in a fixed ratio", "A compound can be separated physically; an element cannot", "They are the same thing — both are pure substances"], a: 1, exp: "An element contains only one type of atom (e.g. pure iron). A compound contains two or more types of atoms chemically bonded together in fixed ratios (e.g. water, H2O)." },
    { q: "What is the difference between a compound and a mixture?", o: ["A compound has random proportions; a mixture has fixed proportions", "A compound contains substances chemically bonded in fixed ratios with new properties; a mixture has substances physically combined without bonding, each retaining its own properties", "A compound can be separated by filtration; a mixture cannot", "Mixtures are always liquids; compounds are always solids"], a: 1, exp: "In a compound, elements are chemically bonded in fixed ratios, creating new properties. In a mixture, substances are physically combined with no chemical bonding, each retaining its original properties." },
    { q: "Can a mixture be separated by physical methods?", o: ["No, it requires a chemical reaction to separate", "Yes, because each component retains its own physical properties", "No, mixtures cannot be separated at all", "Only if the mixture contains metals"], a: 1, exp: "Mixtures can be separated by physical techniques (filtration, evaporation, distillation, magnetic separation, etc.) because each component retains its own distinctive physical properties." },
    { q: "What is a homogeneous mixture?", o: ["A mixture with visibly different components (like salad)", "A mixture where components are different states of matter", "A mixture with uniform composition throughout where you cannot see separate components (like salt water)", "A mixture that can only be separated by chemical reactions"], a: 2, exp: "A homogeneous mixture is uniform throughout — the same composition in every part. Saltwater and air are examples. You cannot see the separate components." },
    { q: "What is a heterogeneous mixture?", o: ["A mixture where all particles are the same size", "A mixture with non-uniform composition where different components can often be seen (like soil or salad)", "A mixture that dissolves completely in water", "A type of compound with variable ratios"], a: 1, exp: "A heterogeneous mixture is non-uniform; different components can often be seen separately, like the different particles in soil or granite." },
    { q: "What is the residue in a filtration experiment?", o: ["The liquid that passes through the filter paper", "The solid material that is left behind on the filter paper", "The chemical produced by the reaction", "The filter paper used in the experiment"], a: 1, exp: "The residue is the solid trapped on the filter paper. The liquid that passes through is called the filtrate." },
    { q: "What is winnowing and which knowledge system uses it?", o: ["Boiling to separate liquids — used by European chemists", "Using water to wash out toxins — used by Torres Strait Islander peoples only", "Using wind or breath to separate lighter husks from heavier seeds — a technique used by Aboriginal and Torres Strait Islander peoples", "Using fire to convert a solid to gas — used by desert communities"], a: 2, exp: "Winnowing exploits differences in density and air resistance to separate light husks from heavier grain. Aboriginal and Torres Strait Islander peoples used this technique to process seeds." },
    { q: "What is leaching as a traditional separation technique?", o: ["Using fire to burn impurities from food", "Using running water to wash out soluble toxic or bitter compounds from plant foods", "Grinding seeds into flour to separate edible parts", "Using magnets to remove metallic impurities from soil"], a: 1, exp: "Leaching uses water to dissolve and wash out soluble toxins or bitter compounds from plant foods. Aboriginal peoples used it to make cycad nuts safe to eat." },
    { q: "What is fractional distillation used for industrially?", o: ["Removing salt from seawater", "Separating crude oil into petrol, diesel, kerosene and other products using their different boiling points", "Filtering particles from drinking water", "Separating oxygen from nitrogen in air by colour"], a: 1, exp: "Fractional distillation separates crude oil into fractions (petrol, kerosene, diesel, bitumen, etc.) by heating the oil and condensing vapours at different temperatures in a fractionating tower." },
    { q: "Which instrument is used to accurately measure mass in the laboratory?", o: ["Measuring cylinder", "Spring balance (newton meter)", "Electronic balance", "Thermometer"], a: 2, exp: "An electronic balance accurately measures mass in grams (g) or kilograms (kg). A spring balance measures weight (force) in newtons, not mass." },
    { q: "Why must you read a measuring cylinder at eye level?", o: ["To see the colour of the liquid more clearly", "To avoid parallax error, which occurs when the angle of view causes a false reading", "To keep the cylinder from tipping over", "Because digital balances cannot measure cylinders"], a: 1, exp: "Parallax error occurs when you view the meniscus from above or below eye level. Reading at eye level from the bottom of the meniscus gives the most accurate reading." },
    { q: "A mixture of sand, salt and water is to be separated. Which FIRST step would you use?", o: ["Evaporation, to remove water first", "Filtration, to remove the insoluble sand from the salt water", "Distillation, to separate salt from sand", "Magnetic separation, to attract the salt"], a: 1, exp: "Sand is insoluble and can be removed by filtration first. The filtrate (salt solution) can then be evaporated to recover the salt." },
    { q: "What does particle theory tell us happens when a solid solute dissolves in water?", o: ["The solute particles break into atoms and combine with water atoms", "Water molecules attract and surround individual solute particles, pulling them away from the solid and spreading them evenly through the solution", "The solid melts and becomes a liquid that mixes with the water", "The solid particles compress until they become too small to see"], a: 1, exp: "In dissolution, water molecules attract outer solute particles, surrounding (solvating) them and carrying them through the solution until they are evenly distributed." },
    { q: "What physical property is exploited when chromatography separates dyes in ink?", o: ["Differences in boiling point", "Differences in magnetic properties", "Differences in how strongly each component is attracted to a surface and how soluble each is in the solvent", "Differences in particle size"], a: 2, exp: "Chromatography separates components based on how strongly each is attracted to a stationary surface versus how soluble it is in the moving solvent (mobile phase)." },
    { q: "If you add more solute to a saturated solution, what happens?", o: ["It all dissolves because the solution adjusts", "The extra solute remains undissolved at the bottom", "The solution becomes supersaturated immediately", "The solvent evaporates to make room for more solute"], a: 1, exp: "At saturation, the solution holds the maximum amount of solute for that temperature. Any additional solute remains undissolved at the bottom." },
    { q: "A solution is described as 'dilute'. What does this mean?", o: ["It contains the maximum possible dissolved solute", "It contains a small amount of solute relative to the volume of solvent", "It has been heated to increase solubility", "It contains only the solvent and no solute at all"], a: 1, exp: "A dilute solution contains a relatively small amount of dissolved solute in the solvent — it is the opposite of concentrated." },
    { q: "Why can filtration NOT remove dissolved salt from salt water?", o: ["Because salt is denser than the filter paper", "Because dissolved salt particles are small enough to pass through the tiny pores in filter paper along with the water", "Because salt reacts with the filter paper", "Because filtration only works on gases"], a: 1, exp: "Dissolved salt particles are smaller than the pores in filter paper, so they pass through along with water. Evaporation must be used to remove the water and recover the salt." },
    { q: "In the water cycle, what change of state occurs when water vapour forms a cloud?", o: ["Evaporation — liquid changes to gas", "Sublimation — solid changes to gas", "Condensation — gas changes to liquid (or solid ice crystals)", "Melting — ice changes to liquid"], a: 2, exp: "Clouds form when water vapour (gas) cools and condenses into tiny liquid water droplets or ice crystals — condensation." },
    { q: "A student measures a pebble: mass = 78 g, volume = 30 mL using water displacement. What is the density?", o: ["2340 g/mL", "2.6 g/mL", "0.38 g/mL", "78 g/mL"], a: 1, exp: "Density = mass / volume = 78 / 30 = 2.6 g/mL. This is consistent with many common rocks and pebbles." },
    { q: "A solution contains more dissolved solute than the maximum allowed at that temperature. What type of solution is it?", o: ["Dilute", "Saturated", "Concentrated", "Supersaturated"], a: 3, exp: "A supersaturated solution contains more dissolved solute than the normal saturation point allows; it is unstable and will crystallise when disturbed." },
    { q: "What happens to particles of a liquid when it evaporates?", o: ["They are destroyed", "They slow down and form a solid lattice", "They gain enough energy to overcome attractive forces and escape from the liquid surface as a gas", "They combine with oxygen in the air"], a: 2, exp: "Evaporation occurs when particles at the liquid's surface gain enough energy to break free of attractive forces and escape into the gas phase." },
    { q: "Which of the following correctly classifies seawater?", o: ["Pure substance (compound)", "Element", "Homogeneous mixture (solution)", "Heterogeneous mixture"], a: 2, exp: "Seawater is a homogeneous mixture (solution) of water, salt and many other dissolved substances — it looks uniform throughout." },
    { q: "What property of a substance determines whether it will float or sink in water?", o: ["Its colour", "Its mass alone", "Its density compared to water (1.0 g/mL)", "Its shape"], a: 2, exp: "Whether an object floats or sinks depends on its density relative to water. Objects less dense than 1.0 g/mL float; objects more dense sink." },
    { q: "What are the three states of matter that water exists in naturally on Earth, and where is each found?", o: ["Solid (ice in glaciers), liquid (oceans, rivers), gas (water vapour in the atmosphere)", "Solid (underground), liquid (in clouds), gas (at the ocean surface)", "Solid (in the sky), liquid (underground), gas (in rivers)", "Solid (at the equator), liquid (at the poles), gas (in lakes)"], a: 0, exp: "Water exists as solid ice (glaciers, polar ice caps, snow), liquid water (oceans, rivers, lakes) and gaseous water vapour (atmosphere, clouds) naturally on Earth." },
    { q: "In which state of matter are the attractive forces between particles weakest?", o: ["Solid", "Liquid", "Gas", "The forces are the same in all states"], a: 2, exp: "In a gas, the attractive forces between particles are extremely weak (or negligible) compared to their kinetic energy, which is why gas particles spread out freely." }
  ]
};
